{
var seed = GetInt(parameters, "seed", context.Seed);
        var colsParam = GetInt(parameters, "brickColumns", 4);
        var rowsParam = GetInt(parameters, "brickRows", 8);
        // Gap width provided in pixels (integer) for explicit control
        var gapWidthPixels = GetInt(parameters, "gapWidth", 2);

        // Enforce even-only semantics for columns, rows, and gap width.
        colsParam = Math.Max(2, Math.Min(colsParam, 10));
        if ((colsParam & 1) != 0) colsParam++;
        rowsParam = Math.Max(2, Math.Min(rowsParam, 10));
        if ((rowsParam & 1) != 0) rowsParam++;
        gapWidthPixels = Math.Max(2, Math.Min(gapWidthPixels, 8));
        if ((gapWidthPixels & 1) != 0) gapWidthPixels++;
        var offset = GetFloat(parameters, "offset", 0.5f);
        var brickColor = GetColor(parameters, "brickColor", Color.FromRgb(140, 89, 64));
        var brickR = brickColor.R / 255f;
        var brickG = brickColor.G / 255f;
        var brickB = brickColor.B / 255f;
        var gapColor = GetColor(parameters, "gapColor", Color.FromRgb(77, 64, 51));
        var gapR = gapColor.R / 255f;
        var gapG = gapColor.G / 255f;
        var gapB = gapColor.B / 255f;
        var colorVar = GetFloat(parameters, "colorVariation", 0.1f);
        var gapDepth = GetFloat(parameters, "gapDepth", 0.3f);
        var edgeRoughness = GetFloat(parameters, "edgeRoughness", 0f);
        var wear = GetFloat(parameters, "wear", 0f);
        var roundness = GetFloat(parameters, "roundness", 0f);
        var brickDetail = GetFloat(parameters, "brickDetail", 0.2f);

        var size = context.TileSize;
        // Use explicit column/row counts provided by the user. Clamp to at
        // least 2 because parameters are even-only and minimum is 2.
        var cols = Math.Max(2, colsParam);
        var rows = Math.Max(2, rowsParam);
        var brickIndexCountU = cols;
        var brickIndexCountV = rows;
        var effBrickW = 1f / cols;
        var effBrickH = 1f / rows;

        var buffer = new PixelBuffer(size, size);

            buffer.ParallelForEachPixel((x, y) =>
            {
                // Sample at pixel centers so CPU output matches GPU/preview sampling
                var u = (x + 0.5f) / (float)size;
                var v = (y + 0.5f) / (float)size;

            float localU, localV;
            int row, brickCol;
            row = (int)MathF.Floor(v / effBrickH);
            var rowOffset = (row % 2 == 1) ? offset * effBrickW : 0f;
            localU = ((u + rowOffset) % effBrickW) / effBrickW;
            localV = (v % effBrickH) / effBrickH;
            brickCol = (int)MathF.Floor((u + rowOffset) / effBrickW);

            // Edge roughness via noise perturbation
            if (edgeRoughness > 0f)
            {
                var noiseVal = TileableFractalNoise(x * 0.3f, y * 0.3f, Math.Max(1, size / 3), 2, 0.5f, 2f, seed + 500);
                localU += (noiseVal - 0.5f) * edgeRoughness * 0.15f;
                localV += (noiseVal - 0.5f) * edgeRoughness * 0.15f;
            }

            // Gap with optional roundness
            // `gapWidth` is now an integer pixel value. Distances are computed
            // in pixel units and compared against this absolute pixel seam
            // width so the seam appears the requested number of pixels wide
            // regardless of the brick count.
            float distU = MathF.Min(localU, 1f - localU);
            float distV = MathF.Min(localV, 1f - localV);

            var tileSizeU = effBrickW;
            var tileSizeV = effBrickH;

            // Convert local distances to pixel units along the local axes
            var brickPixelU = tileSizeU * size;
            var brickPixelV = tileSizeV * size;
            var distUPixels = distU * brickPixelU;
            var distVPixels = distV * brickPixelV;

            // Desired seam width in pixels (absolute pixel units). The actual
            // per-brick comparison uses half the seam so adjacent bricks don't
            // each contribute the full seam width (avoids double-thick seams).
            var gapPixels = gapWidthPixels;
            var gapHalf = gapPixels * 0.5f;

            if (roundness > 0f)
            {
                // Rounded corners: compute a corner radius in pixels based on
                // the brick size so rounding scales with brick dimensions.
                var radius = roundness * MathF.Min(brickPixelU, brickPixelV) * 0.5f;

                // Distances from the inner rectangular seam boundary. If either
                // distance is <= 0 we're already inside the rectangular seam.
                var du = MathF.Max(0f, distUPixels - gapHalf);
                var dv = MathF.Max(0f, distVPixels - gapHalf);

                // Distance into the corner region
                var cornerDist = MathF.Sqrt(du * du + dv * dv);

                // Inside seam if within rectangular seam or within corner radius
                var isGapRect = distUPixels <= gapHalf || distVPixels <= gapHalf;
                if (isGapRect || cornerDist <= radius)
                {
                    var depthFactor = Math.Clamp(gapDepth, 0f, 1f);
                    // t: 0 at the outer edge, 1 at the deepest interior of corner
                    var t = Math.Clamp((radius - cornerDist) / Math.Max(radius, 0.001f), 0f, 1f);
                    var gr = Lerp(gapR, gapR * (1f - depthFactor * 0.5f), t);
                    var gg = Lerp(gapG, gapG * (1f - depthFactor * 0.5f), t);
                    var gb = Lerp(gapB, gapB * (1f - depthFactor * 0.5f), t);
                    buffer.SetPixel(x, y, gr, gg, gb, 1f);
                    return;
                }
            }
            else
            {
                // No rounding: simple pixel-space comparison so seam width in
                // pixels is controlled directly by the integer pixel parameter.
                // Use half-width per-brick so the seam between bricks equals
                // the requested pixel count instead of doubling it.
                var isGap = distUPixels <= gapHalf || distVPixels <= gapHalf;
                if (isGap)
                {
                    // Textured seam for non-rounded case
                    var depthFactor = Math.Clamp(gapDepth, 0f, 1f);
                    var seamDist = MathF.Min(distUPixels, distVPixels) / MathF.Max(gapHalf, 0.001f);
                    seamDist = Math.Clamp(seamDist, 0f, 1f);

                    var seamNoise = TileableFractalNoise(x * 0.6f, y * 0.6f, Math.Max(1, size / 3), 3, 0.55f, 2f, seed + 12345 + brickCol * 97 + row * 193);
                    var coreDarkFactor = 1f - depthFactor * 0.6f * (1f + (seamNoise - 0.5f) * 0.6f);
                    coreDarkFactor = Math.Clamp(coreDarkFactor, 0.4f, 1f);

                    var gr = Lerp(gapR * coreDarkFactor, gapR, seamDist);
                    var gg = Lerp(gapG * coreDarkFactor, gapG, seamDist);
                    var gb = Lerp(gapB * coreDarkFactor, gapB, seamDist);

                    // Slight vertical/horizontal variation to break flatness
                    var speck = TileableFractalNoise((x + 17) * 1.6f, (y + 11) * 1.9f, Math.Max(1, size / 3), 1, 0.5f, 2f, seed + 773);
                    var speckAdj = (speck - 0.5f) * 0.08f * (1f - seamDist);
                    gr = Math.Clamp(gr + speckAdj, 0f, 1f);
                    gg = Math.Clamp(gg + speckAdj * 0.95f, 0f, 1f);
                    gb = Math.Clamp(gb + speckAdj * 0.9f, 0f, 1f);

                    buffer.SetPixel(x, y, gr, gg, gb, 1f);
                    return;
                }
            }

            // Per-brick color variation (use modulo indices so variation is
            // tileable across the full tile). Use the precomputed index counts
            // to support layouts that double the index grid (weave).
            var ix = brickCol % brickIndexCountU;
            var iy = row % brickIndexCountV;
            var variation = (HashToUnit(ix, iy, seed) - 0.5f) * 2f * colorVar;
            var r = Math.Clamp(brickR + variation, 0f, 1f);
            var g = Math.Clamp(brickG + variation * 0.8f, 0f, 1f);
            var b = Math.Clamp(brickB + variation * 0.6f, 0f, 1f);

            // Add per-brick procedural detail inspired by StoneGenerator:
            // - center lift, light bias, multi-frequency surface noise,
            // - tonal push/pull and subtle speckle. All noise is tileable.
            if (brickDetail > 0f)
            {
                var blockHash = HashToUnit(ix, iy, seed + 200);

                // center-based lift (stronger toward the brick center)
                var cdx = localU - 0.5f;
                var cdy = localV - 0.5f;
                var cdist = MathF.Sqrt(cdx * cdx + cdy * cdy);
                var centerLift = Math.Clamp((0.72f - cdist) / Math.Max(0.001f, (0.72f - 0.12f)), 0f, 1f);

                // lighting bias to give subtle directional shading
                var lightBias = (1f - localU) * 0.38f + (1f - localV) * 0.62f;

                // multi-frequency tileable surface noise
                var freqA = 0.35f + blockHash * 0.25f;
                var freqB = 0.9f + (1f - blockHash) * 1.1f;
                var s1 = TileableFractalNoise(x * freqA, y * freqA, Math.Max(1, size / 3), 3, 0.55f, 2f, seed + 70 + ix * 17 + iy * 31);
                var s2 = TileableFractalNoise(x * freqB, y * freqB, Math.Max(1, size / 3), 2, 0.5f, 2f, seed + 170 + ix * 13 + iy * 29);
                var surfaceNoise = s1 * 0.62f + s2 * 0.38f;

                // Compose a tone influence from the factors above
                var tone = 0f;
                tone += (blockHash - 0.5f) * 0.18f; // subtle per-brick bias
                tone += centerLift * 0.34f;
                tone += (lightBias - 0.5f) * 0.22f;
                tone += (surfaceNoise - 0.5f) * 0.36f;

                // Apply tonal push: positive -> lighter, negative -> darker
                var toneClamp = Math.Clamp(tone, -0.5f, 0.8f);
                if (toneClamp >= 0f)
                {
                    var lighterR = Math.Clamp(r + 0.12f, 0f, 1f);
                    var lighterG = Math.Clamp(g + 0.12f, 0f, 1f);
                    var lighterB = Math.Clamp(b + 0.09f, 0f, 1f);
                    var t = toneClamp / 0.8f;
                    r = Lerp(r, lighterR, t);
                    g = Lerp(g, lighterG, t);
                    b = Lerp(b, lighterB, t);
                }
                else
                {
                    var darkerR = Math.Clamp(r - 0.12f, 0f, 1f);
                    var darkerG = Math.Clamp(g - 0.12f, 0f, 1f);
                    var darkerB = Math.Clamp(b - 0.09f, 0f, 1f);
                    var t = -toneClamp / 0.5f;
                    r = Lerp(r, darkerR, t);
                    g = Lerp(g, darkerG, t);
                    b = Lerp(b, darkerB, t);
                }

                // Add fine-grained speckle/grit
                var speck = TileableFractalNoise((x + 37) * 2.3f, (y + 19) * 2.7f, Math.Max(1, size / 3), 1, 0.5f, 2f, seed + 503);
                var speckVal = (speck - 0.5f) * 0.18f * brickDetail;
                r = Math.Clamp(r + speckVal, 0f, 1f);
                g = Math.Clamp(g + speckVal * 0.85f, 0f, 1f);
                b = Math.Clamp(b + speckVal * 0.7f, 0f, 1f);
            }

            // Wear/aging effect: blend toward lighter desaturated color near edges
            if (wear > 0f)
            {
                var wearNoise = HashToUnit(brickCol + 17, row + 23, seed + 999);
                var wearAmount = wearNoise * wear;
                var edgeFactor = 1f - MathF.Min(distU / 0.3f, distV / 0.3f);
                edgeFactor = Math.Clamp(edgeFactor, 0f, 1f);
                var wearBlend = wearAmount * edgeFactor;
                var wearR = (r + g + b) / 3f * 1.1f;
                r = Lerp(r, Math.Clamp(wearR, 0f, 1f), wearBlend);
                g = Lerp(g, Math.Clamp(wearR, 0f, 1f), wearBlend);
                b = Lerp(b, Math.Clamp(wearR * 0.95f, 0f, 1f), wearBlend);
            }

            buffer.SetPixel(x, y, r, g, b, 1f);
        });

        return buffer;
}
